/* ferment-co rustic rectilinear overrides */

/* Page background and surface */
body.theme-ferment-co{background-color:var(--wp--preset--color--base);}

/* Section vertical rhythm — unhurried homestead pacing */
body.theme-ferment-co .wp-block-group.alignfull{padding-top:var(--wp--preset--spacing--xl);padding-bottom:var(--wp--preset--spacing--xl);}

/* Section headings: EB Garamond 700, high-contrast on base */
body.theme-ferment-co h1,
body.theme-ferment-co h2,
body.theme-ferment-co h3,
body.theme-ferment-co .wp-block-query-title,
body.theme-ferment-co .wp-block-post-title{font-family:var(--wp--preset--font-family--display);font-weight:700;color:var(--wp--preset--color--contrast);letter-spacing:-0.01em;}

/* Body and dek: Lora 400 */
body.theme-ferment-co p,
body.theme-ferment-co li,
body.theme-ferment-co .wp-block-post-excerpt__excerpt{font-family:var(--wp--preset--font-family--sans);font-weight:400;color:var(--wp--preset--color--secondary);}

/* Eyebrows / labels: Lora 500 uppercase tracked */
body.theme-ferment-co .wp-block-post-terms,
body.theme-ferment-co .wc-block-components-product-category-list,
body.theme-ferment-co .wc-block-components-product-badge,
body.theme-ferment-co figcaption{font-family:var(--wp--preset--font-family--sans);font-weight:500;text-transform:uppercase;letter-spacing:0.1em;font-size:0.75em;color:var(--wp--preset--color--tertiary);}

/* CTA buttons: accent fill, cream text, no border-radius, 2px secondary border on hover */
body.theme-ferment-co .wp-block-button__link,
body.theme-ferment-co .wc-block-components-button,
body.theme-ferment-co .wc-block-cart__submit-button,
body.theme-ferment-co .wc-block-components-checkout-place-order-button,
body.theme-ferment-co .wo-empty__cta--primary,
body.theme-ferment-co .selvedge-footer__newsletter-submit{background-color:var(--wp--preset--color--accent);color:var(--wp--preset--color--surface);border-radius:0;border:2px solid transparent;font-family:var(--wp--preset--font-family--sans);font-weight:500;text-transform:uppercase;letter-spacing:0.08em;}

body.theme-ferment-co .wp-block-button__link:hover,
body.theme-ferment-co .wc-block-components-button:hover,
body.theme-ferment-co .wc-block-cart__submit-button:hover,
body.theme-ferment-co .wc-block-components-checkout-place-order-button:hover,
body.theme-ferment-co .wo-empty__cta--primary:hover,
body.theme-ferment-co .selvedge-footer__newsletter-submit:hover{background-color:var(--wp--preset--color--primary-hover);color:var(--wp--preset--color--surface);border-color:var(--wp--preset--color--secondary);}

/* Product cards and category tiles: surface fill, 2px border-color border, no shadow, 2px radius */
body.theme-ferment-co .wc-block-components-product-card,
body.theme-ferment-co .wp-block-woocommerce-product-template .wp-block-post,
body.theme-ferment-co .wc-block-product-template .wc-block-grid__product,
body.theme-ferment-co .wp-block-woocommerce-handpicked-products .wc-block-grid__product,
body.theme-ferment-co .wo-product-card{background-color:var(--wp--preset--color--surface);border:2px solid var(--wp--preset--color--border);border-radius:2px;box-shadow:none;}

/* Category strip tiles: accent-soft fill, accent label, border-color border */
body.theme-ferment-co .wp-block-query.is-category-strip .wp-block-post,
body.theme-ferment-co .ferment-category-tile,
body.theme-ferment-co .wp-block-categories-list .wp-block-categories__item,
body.theme-ferment-co .wc-block-product-categories .wc-block-product-categories__list-item{background-color:var(--wp--preset--color--accent-soft);border:2px solid var(--wp--preset--color--border);border-radius:2px;color:var(--wp--preset--color--accent);font-family:var(--wp--preset--font-family--sans);font-weight:500;text-transform:uppercase;letter-spacing:0.08em;}

body.theme-ferment-co .wp-block-categories-list .wp-block-categories__item a,
body.theme-ferment-co .wc-block-product-categories .wc-block-product-categories__list-item a{color:var(--wp--preset--color--accent);}

/* Card separator: subtle bottom-border, no shadow */
body.theme-ferment-co .wc-block-components-product-card,
body.theme-ferment-co .wo-product-card{border-bottom:2px solid var(--wp--preset--color--subtle);}

/* Inter-card gap: spacing--md */
body.theme-ferment-co .wp-block-query .wp-block-post-template,
body.theme-ferment-co .wc-block-product-template,
body.theme-ferment-co .wc-block-grid__products{gap:var(--wp--preset--spacing--md);}

/* Footer signup band: surface bg, full-width, 2px border-color top border */
body.theme-ferment-co footer.wp-block-template-part,
body.theme-ferment-co .selvedge-footer,
body.theme-ferment-co .wp-block-group.is-footer-newsletter{background-color:var(--wp--preset--color--surface);border-top:2px solid var(--wp--preset--color--border);}

/* Links in body copy */
body.theme-ferment-co a{color:var(--wp--preset--color--accent);}
body.theme-ferment-co a:hover{color:var(--wp--preset--color--primary-hover);}

/* Input fields: parchment bg, border-color border, no radius */
body.theme-ferment-co input[type="text"],
body.theme-ferment-co input[type="email"],
body.theme-ferment-co input[type="search"],
body.theme-ferment-co input[type="number"],
body.theme-ferment-co textarea,
body.theme-ferment-co select{background-color:var(--wp--preset--color--base);border:2px solid var(--wp--preset--color--muted);border-radius:0;color:var(--wp--preset--color--contrast);font-family:var(--wp--preset--font-family--sans);}

body.theme-ferment-co input:focus,
body.theme-ferment-co textarea:focus,
body.theme-ferment-co select:focus{border-color:var(--wp--preset--color--border);outline:none;box-shadow:none;}

/* WooCommerce price: accent color, display font */
body.theme-ferment-co .wc-block-components-product-price,
body.theme-ferment-co .price,
body.theme-ferment-co .woocommerce-Price-amount{color:var(--wp--preset--color--accent);font-family:var(--wp--preset--font-family--display);font-weight:600;}

/* Out of stock / out of culture styling */
body.theme-ferment-co .wc-block-components-product-stock-indicator,
body.theme-ferment-co .out-of-stock{color:var(--wp--preset--color--muted);font-style:italic;font-family:var(--wp--preset--font-family--sans);}

/* Hover polarity fix for ferment-co class */
body.theme-ferment-co.theme-ferment-co .wc-block-mini-cart__footer-actions a:hover,
body.theme-ferment-co.theme-ferment-co .wc-block-components-totals-coupon__button:hover,
body.theme-ferment-co.theme-ferment-co .wc-block-cart__submit-container .wc-block-components-checkout-place-order-button:hover,
body.theme-ferment-co.theme-ferment-co .wo-empty__cta--primary:hover,
body.theme-ferment-co.theme-ferment-co .selvedge-footer__newsletter-submit:hover{background-color:var(--wp--preset--color--primary-hover);color:var(--wp--preset--color--surface);border-color:var(--wp--preset--color--secondary);}
/* /ferment-co rustic rectilinear overrides */
